import{_ as a,o as d,c as r,ag as e}from"./chunks/framework.Vng7Hdlh.js";const u=JSON.parse('{"title":"17. セルフオーダー画面（お客さん向け）","description":"","frontmatter":{},"headers":[],"relativePath":"tenant/17-customer.md","filePath":"tenant/17-customer.md"}'),l={name:"tenant/17-customer.md"};function h(i,t,o,n,b,s){return d(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="_17-セルフオーダー画面-お客さん向け" tabindex="-1">17. セルフオーダー画面（お客さん向け） <a class="header-anchor" href="#_17-セルフオーダー画面-お客さん向け" aria-label="Permalink to &quot;17. セルフオーダー画面（お客さん向け）&quot;">​</a></h1><p>セルフオーダー画面（<code>/customer/menu.html</code>）は、お客さんがスマートフォンでQRコードを読み取って注文する画面です。テーブルのQRコードを読み取ると、そのテーブル専用の注文画面が開きます。</p><h2 id="_17-1-画面構成" tabindex="-1">17.1 画面構成 <a class="header-anchor" href="#_17-1-画面構成" aria-label="Permalink to &quot;17.1 画面構成&quot;">​</a></h2><h3 id="ヘッダー" tabindex="-1">ヘッダー <a class="header-anchor" href="#ヘッダー" aria-label="Permalink to &quot;ヘッダー&quot;">​</a></h3><table tabindex="0"><thead><tr><th>要素</th><th>説明</th></tr></thead><tbody><tr><td>店舗名</td><td>店舗のブランド名（設定されている場合はロゴも表示）</td></tr><tr><td>テーブルコード</td><td>「テーブル A-1」形式</td></tr><tr><td>テイクアウトリンク</td><td>テイクアウトが有効な場合に表示</td></tr><tr><td>言語セレクター</td><td>多言語切替ボタン</td></tr></tbody></table><h3 id="言語切替" tabindex="-1">言語切替 <a class="header-anchor" href="#言語切替" aria-label="Permalink to &quot;言語切替&quot;">​</a></h3><p>proプラン以上で多言語対応が有効な場合、以下の5言語から切替できます。</p><table tabindex="0"><thead><tr><th>言語</th><th>フラグ</th></tr></thead><tbody><tr><td>日本語</td><td>🇯🇵</td></tr><tr><td>English</td><td>🇺🇸</td></tr><tr><td>简体中文</td><td>🇨🇳</td></tr><tr><td>繁體中文</td><td>🇹🇼</td></tr><tr><td>한국어</td><td>🇰🇷</td></tr></tbody></table><h3 id="バナー表示" tabindex="-1">バナー表示 <a class="header-anchor" href="#バナー表示" aria-label="Permalink to &quot;バナー表示&quot;">​</a></h3><p>状況に応じて以下のバナーが表示されます。</p><table tabindex="0"><thead><tr><th>バナー</th><th>条件</th><th>内容</th></tr></thead><tbody><tr><td>プランバナー</td><td>食べ放題プラン利用中</td><td>プラン名・残り時間</td></tr><tr><td>コースバナー</td><td>コース料理利用中</td><td>コース名・現在のフェーズ</td></tr><tr><td>ラストオーダーバナー</td><td>ラストオーダー発動中</td><td>注文受付終了の案内</td></tr></tbody></table><h3 id="メインコンテンツ" tabindex="-1">メインコンテンツ <a class="header-anchor" href="#メインコンテンツ" aria-label="Permalink to &quot;メインコンテンツ&quot;">​</a></h3><table tabindex="0"><thead><tr><th>セクション</th><th>説明</th></tr></thead><tbody><tr><td>カテゴリナビゲーション</td><td>メニューカテゴリのタブ</td></tr><tr><td>注文ステータス</td><td>リアルタイムの注文進捗（トラッカー）</td></tr><tr><td>リオーダーセクション</td><td>前回の注文からの再注文</td></tr><tr><td>メニュー一覧</td><td>メニュー品目のグリッド表示</td></tr></tbody></table><hr><h2 id="_17-2-注文の流れ" tabindex="-1">17.2 注文の流れ <a class="header-anchor" href="#_17-2-注文の流れ" aria-label="Permalink to &quot;17.2 注文の流れ&quot;">​</a></h2><h3 id="ステップ1-qrコードを読み取る" tabindex="-1">ステップ1：QRコードを読み取る <a class="header-anchor" href="#ステップ1-qrコードを読み取る" aria-label="Permalink to &quot;ステップ1：QRコードを読み取る&quot;">​</a></h3><ol><li>テーブルに設置されたQRコードをスマートフォンのカメラで読み取ります</li><li>セルフオーダー画面が開きます</li><li>店舗のブランドカラーとロゴが適用された画面が表示されます</li></ol><h3 id="ステップ2-メニューを選ぶ" tabindex="-1">ステップ2：メニューを選ぶ <a class="header-anchor" href="#ステップ2-メニューを選ぶ" aria-label="Permalink to &quot;ステップ2：メニューを選ぶ&quot;">​</a></h3><ol><li>カテゴリタブでカテゴリを選択します</li><li>メニュー品目をタップします</li><li>オプションがある場合はオプション選択画面が表示されます</li><li>品目がカートに追加されます</li></ol><h3 id="ステップ3-カートを確認する" tabindex="-1">ステップ3：カートを確認する <a class="header-anchor" href="#ステップ3-カートを確認する" aria-label="Permalink to &quot;ステップ3：カートを確認する&quot;">​</a></h3><p>画面下部にカートバーが表示されます。</p><table tabindex="0"><thead><tr><th>要素</th><th>説明</th></tr></thead><tbody><tr><td>品目数</td><td>カート内の品目数</td></tr><tr><td>合計金額</td><td>—</td></tr><tr><td>「注文を確認」ボタン</td><td>カート詳細を開く</td></tr></tbody></table><h3 id="ステップ4-注文を送信する" tabindex="-1">ステップ4：注文を送信する <a class="header-anchor" href="#ステップ4-注文を送信する" aria-label="Permalink to &quot;ステップ4：注文を送信する&quot;">​</a></h3><ol><li>「注文を確認」ボタンをタップします</li><li>チェックアウトモーダルが開きます</li><li>注文内容を最終確認します</li><li><strong>ひとことメモ：</strong> 最大200文字のメモを追加できます</li><li><strong>アレルゲン選択チップ：</strong> 以下のアレルゲンを選択して申告できます</li></ol><table tabindex="0"><thead><tr><th>アレルゲン</th></tr></thead><tbody><tr><td>卵</td></tr><tr><td>乳</td></tr><tr><td>小麦</td></tr><tr><td>えび</td></tr><tr><td>かに</td></tr><tr><td>そば</td></tr><tr><td>落花生</td></tr></tbody></table><ol start="6"><li>「注文する」ボタンをタップして注文を確定します</li></ol><h3 id="注文のリトライ機能" tabindex="-1">注文のリトライ機能 <a class="header-anchor" href="#注文のリトライ機能" aria-label="Permalink to &quot;注文のリトライ機能&quot;">​</a></h3><p>ネットワークエラーが発生した場合：</p><ul><li>自動的に最大2回リトライされます（2秒間隔）</li><li>冪等性キー（ランダムな32文字の16進数）により、重複注文が防止されます</li><li>完全にオフラインの場合、注文はブラウザのlocalStorageに保存され、接続復旧時に自動送信されます</li><li>24時間以上経過した保留注文は自動破棄されます</li></ul><hr><h2 id="_17-3-注文ステータスのリアルタイム追跡" tabindex="-1">17.3 注文ステータスのリアルタイム追跡 <a class="header-anchor" href="#_17-3-注文ステータスのリアルタイム追跡" aria-label="Permalink to &quot;17.3 注文ステータスのリアルタイム追跡&quot;">​</a></h2><p>注文送信後、画面上部に注文の進捗がリアルタイムで表示されます。</p><h3 id="ポーリング間隔" tabindex="-1">ポーリング間隔 <a class="header-anchor" href="#ポーリング間隔" aria-label="Permalink to &quot;ポーリング間隔&quot;">​</a></h3><p>5秒ごとに注文ステータスが更新されます。</p><h3 id="ステータス表示" tabindex="-1">ステータス表示 <a class="header-anchor" href="#ステータス表示" aria-label="Permalink to &quot;ステータス表示&quot;">​</a></h3><table tabindex="0"><thead><tr><th>ステータス</th><th>バッジ</th><th>意味</th></tr></thead><tbody><tr><td>pending</td><td>受付済み</td><td>注文がキッチンに届きました</td></tr><tr><td>preparing</td><td>調理中</td><td>調理を開始しました</td></tr><tr><td>ready</td><td>完成</td><td>料理ができました</td></tr><tr><td>served</td><td>提供済</td><td>テーブルに届けました</td></tr><tr><td>cancelled</td><td>キャンセル</td><td>注文がキャンセルされました</td></tr></tbody></table><h3 id="プログレスバー" tabindex="-1">プログレスバー <a class="header-anchor" href="#プログレスバー" aria-label="Permalink to &quot;プログレスバー&quot;">​</a></h3><p>注文全体の進捗を視覚的に表示します。全品目が「served」になると完了です。</p><hr><h2 id="_17-4-スタッフ呼び出し" tabindex="-1">17.4 スタッフ呼び出し <a class="header-anchor" href="#_17-4-スタッフ呼び出し" aria-label="Permalink to &quot;17.4 スタッフ呼び出し&quot;">​</a></h2><p>画面のヘッダーにある🔔アイコンをタップすると、スタッフ呼び出し機能が利用できます。</p><h3 id="呼び出しの種類" tabindex="-1">呼び出しの種類 <a class="header-anchor" href="#呼び出しの種類" aria-label="Permalink to &quot;呼び出しの種類&quot;">​</a></h3><table tabindex="0"><thead><tr><th>選択肢</th><th>説明</th></tr></thead><tbody><tr><td>注文したい</td><td>注文に関する呼び出し</td></tr><tr><td>お会計をお願いします</td><td>会計リクエスト</td></tr><tr><td>食器を下げてください</td><td>下げ物の依頼</td></tr><tr><td>その他</td><td>自由入力</td></tr></tbody></table><h3 id="呼び出しの流れ" tabindex="-1">呼び出しの流れ <a class="header-anchor" href="#呼び出しの流れ" aria-label="Permalink to &quot;呼び出しの流れ&quot;">​</a></h3><ol><li>🔔アイコンをタップします</li><li>呼び出し理由を選択します</li><li>スタッフのハンディPOSとKDSにアラートが表示されます</li><li>スタッフが「対応済み」をタップすると、お客さんの画面に効果音（440Hz→523Hz）で通知されます</li></ol><h3 id="クールダウン" tabindex="-1">クールダウン <a class="header-anchor" href="#クールダウン" aria-label="Permalink to &quot;クールダウン&quot;">​</a></h3><p>呼び出し後、3分間は次の呼び出しができません（カウントダウン表示）。これにより連打による誤発信を防止します。</p><hr><h2 id="_17-5-カートの永続化" tabindex="-1">17.5 カートの永続化 <a class="header-anchor" href="#_17-5-カートの永続化" aria-label="Permalink to &quot;17.5 カートの永続化&quot;">​</a></h2><p>カートの内容はブラウザのlocalStorageに保存されます。</p><ul><li>ページをリロードしてもカートの内容は維持されます</li><li>セッショントークンが変わった場合（テーブルリセット後）、カートは自動クリアされます</li></ul><h3 id="迷い品目トラッキング" tabindex="-1">迷い品目トラッキング <a class="header-anchor" href="#迷い品目トラッキング" aria-label="Permalink to &quot;迷い品目トラッキング&quot;">​</a></h3><p>カートに追加した後に削除した品目は「迷い品目」として記録され、オーナーダッシュボードのクロス店舗レポートで分析できます。これにより、お客さんが迷ったメニューの改善に活用できます。</p><hr><h2 id="_17-6-ラストオーダー" tabindex="-1">17.6 ラストオーダー <a class="header-anchor" href="#_17-6-ラストオーダー" aria-label="Permalink to &quot;17.6 ラストオーダー&quot;">​</a></h2><p>ラストオーダーが発動されると、セルフオーダー画面では新規注文がブロックされます。</p><ul><li>画面にラストオーダーバナーが表示されます</li><li>「注文する」ボタンが無効化されます</li><li>注文送信時にサーバー側でもラストオーダーチェックが行われ、<code>LAST_ORDER_PASSED</code>エラーが返されます</li></ul>',57)])])}const q=a(l,[["render",h]]);export{u as __pageData,q as default};
